#!/usr/bin/env node
const fs   = require('fs');
const path = require('path');
const ROOT = process.cwd();

function backup(fp) { if (fs.existsSync(fp)) fs.copyFileSync(fp, fp + '.bak3'); }
function write(rel, content) {
  const full = path.join(ROOT, rel);
  backup(full);
  fs.mkdirSync(path.dirname(full), { recursive: true });
  fs.writeFileSync(full, content, 'utf-8');
  console.log('  ✔', rel);
}

// 1. CSS
const newCss = fs.readFileSync('/tmp/style-new.css', 'utf-8');
write('frontend/css/style.css', newCss);

// 2. HTML
const htmlPath = path.join(ROOT, 'frontend/index.html');
if (!fs.existsSync(htmlPath)) { console.log('  x index.html tidak ada'); process.exit(1); }
backup(htmlPath);
let html = fs.readFileSync(htmlPath, 'utf-8');

// ── Topbar ──────────────────────────────────────────────────────────────────
const newTopbar = `<div class="topbar">
    <div class="tb-logo">
      <div class="tb-mark">π</div>
      <div class="tb-name-block">
        <div class="tb-title">E-Kamatho</div>
        <div class="tb-sub">Pi Payment · TransFi Offramp</div>
      </div>
    </div>
    <div class="tb-right">
      <div class="notif-btn" onclick="openNotif()">🔔<div class="notif-btn-dot"></div></div>
      <div class="user-pill" onclick="showProfile()">
        <div class="user-avatar" id="uav">π</div>
        <span id="uname" class="user-name">@—</span>
        <span class="user-chevron">▾</span>
      </div>
    </div>
  </div>`;

// Ganti topbar lama
html = html.replace(/<div class="topbar">[\s\S]*?<\/div>\s*<\/div>\s*(?=\n\s*<div class="balance-hero")/, newTopbar + '\n\n  ');

// ── Balance hero ─────────────────────────────────────────────────────────────
